#include <memory>
#include <string>
#include <new>
#include <cstddef>
#include <print>

int main() {
    // Замена std::aligned_storage — идиома с alignas и std::byte:
    alignas(int) std::byte storage[sizeof(int)];
    new (storage) int{42};
    int* p = std::launder(reinterpret_cast<int*>(storage));
    std::println("value from aligned storage: {}", *p);
    // int тривиально разрушаем — явный деструктор не нужен

    // Замена reserve() без аргументов:
    std::string s = "Hello, this is a string that was previously longer";
    s = "short";
    s.shrink_to_fit(); // вместо устаревшего s.reserve()
    std::println("after shrink_to_fit, size: {}, capacity >= size: {}",
        s.size(), s.capacity() >= s.size());

    // Корректная конкатенация — только однотипные литералы:
    const char* combined = "hello" " " "world"; // OK — все узкие
    std::println("combined: {}", combined);
}

#include <cstdint>
#include <print>

// Scoped enum с явным базовым типом — никакой неоднозначности сужения:
enum class Register : uint8_t {
    STATUS  = 0x00,
    CONTROL = 0x01,
    DATA    = 0x02
};

// Корректное использование volatile: симуляция аппаратного регистра
volatile uint8_t hw_register = 0;

void write_register(Register reg, uint8_t value) {
    // В реальном коде — запись в memory-mapped регистр
    hw_register = value;
    std::println("wrote {:02x} to register {:02x}",
        value, static_cast<uint8_t>(reg));
}

int main() {
    // Инициализация enum — только допустимые значения:
    Register r = Register::CONTROL;
    std::println("register value: {}", static_cast<int>(r));

    write_register(Register::DATA, 0xFF);
    // volatile нельзя напрямую передать в std::format — нужен cast:
    std::println("hw_register: {}", static_cast<uint8_t>(hw_register));

    // Конкатенация строк — только однотипные литералы:
    const char* greeting = "C++" "23"; // OK
    std::println("standard: {}", greeting);
}
